module RefModule(gclk,clk,enable,scan_enable);output gclk; 
 input clk; 
 input enable; 
 input scan_enable; 
 wire enable_in = (enable | scan_enable); 
 reg enable_latch; 
 always @(clk or enable_in) 
  if (~clk) 
  enable_latch <= enable_in; 
 wire __gclk_tmp = (clk & enable_latch);
 assign gclk = __gclk_tmp; 
 endmodule
